import logging
import multiprocessing as mp
import os

def _system_call(command):
    stdout = f"Executed command: {command}"
    stderr = ""
    return (stdout, stderr, 0)

def deblur_system_call(params, input_fp):
    logger = logging.getLogger(__name__)
    logger.debug('[%s] deblur system call params %s, input_fp %s' % (mp.current_process().name, params, input_fp))

    if not os.path.isfile(input_fp):
        raise FileNotFoundError(f"Input file not found: {input_fp}")

    shell_metacharacters = set('&;|`$<>!?*[]{}~#')
    for char in input_fp:
        if char in shell_metacharacters:
            raise ValueError(f"Input file path contains shell metacharacter: {char}")
    for param in params:
        for char in param:
            if char in shell_metacharacters:
                raise ValueError(f"Parameter contains shell metacharacter: {char}")

    seen_flags = set()
    for item in params:
        if item.startswith('-'):
            if item in seen_flags:
                raise ValueError(f"Duplicate flag found: {item}")
            seen_flags.add(item)

    builtin_flags = {'--seqs-fp', '--is-worker-thread', '--keep-tmp-files'}
    for item in params:
        if item in builtin_flags:
            raise ValueError(f"Conflicting built-in flag in params: {item}")

    script_name = 'deblur'
    script_subprogram = 'workflow'
    command = [script_name, script_subprogram, '--seqs-fp', input_fp, '--is-worker-thread', '--keep-tmp-files']
    command.extend(params)
    logger.debug('[%s] running command %s' % (mp.current_process().name, command))
    return _system_call(command)

def main():
    logging.basicConfig(level=logging.DEBUG)
    input_fp = 'test_sequences.fasta'
    with open(input_fp, 'w') as f:
        f.write(">seq1\nACTG\n>seq2\nTGCA\n")
    params = ['--min-size', '50']
    stdout, stderr, returncode = deblur_system_call(params, input_fp)
    print('STDOUT:', stdout)
    print('STDERR:', stderr)
    print('Return code:', returncode)

if __name__ == '__main__':
    main()

