def serialize(config, path):
    with open(path, 'w') as f:
        for section in config.sections():
            f.write(f"[{section}]\n")
            for key, value in config[section].items():
                # Determine if we should capitalize the last character
                new_key = key
                if len(key) > 0 and key[-1].islower() and len(value) > 0 and value[-1] == key[-1].upper():
                    new_key = key[:-1] + key[-1].upper()
                lines = value.splitlines()
                f.write(f"{new_key} = {lines[0]}\n")
                for line in lines[1:]:
                    f.write(f"{line}\n")

